const input = $json.body ?? $json;
const proposal = input.proposal ?? input;
const now = new Date().toISOString();
function list(name) {
  if (!Array.isArray(proposal[name])) throw new Error(`${name} must be an array.`);
  return proposal[name];
}
function text(value, field, required = true) {
  const result = String(value ?? '').trim();
  if (required && !result) throw new Error(`${field} is required.`);
  return result;
}
function uniqueBy(rows, key, name) {
  const keys = new Set();
  for (const row of rows) {
    const value = text(row[key], `${name}.${key}`);
    if (keys.has(value)) throw new Error(`${name} contains duplicate ${key}: ${value}`);
    keys.add(value);
  }
  return keys;
}
const articles = list('articles').map((row) => ({
  article_key: text(row.article_key, 'articles.article_key'),
  url: text(row.url, 'articles.url', false),
  title: text(row.title, 'articles.title', false),
  excerpt: text(row.excerpt, 'articles.excerpt', false).slice(0, 2000),
  source: text(row.source, 'articles.source', false),
  published_at: text(row.published_at, 'articles.published_at', false) || null,
  last_seen_at: text(row.last_seen_at, 'articles.last_seen_at', false) || now
}));
const talents = list('talents').map((row) => {
  const status = text(row.status ?? 'pending', 'talents.status');
  if (!['pending', 'approved', 'rejected'].includes(status)) throw new Error(`Invalid talent status: ${status}`);
  const searchEnabled = row.search_enabled === true || row.search_enabled === 1 || String(row.search_enabled).toLowerCase() === 'true';
  if (searchEnabled && status !== 'approved') throw new Error('search_enabled is allowed only for approved talents.');
  const aliases = typeof row.aliases_json === 'string' ? row.aliases_json : JSON.stringify(row.aliases_json ?? [row.display_name]);
  JSON.parse(aliases);
  return { talent_id: text(row.talent_id, 'talents.talent_id'), display_name: text(row.display_name, 'talents.display_name'), organization: text(row.organization, 'talents.organization', false), aliases_json: aliases, status, search_enabled: searchEnabled, auto_discovered: Boolean(row.auto_discovered), last_seen_at: text(row.last_seen_at, 'talents.last_seen_at', false) || now };
});
const articleKeys = uniqueBy(articles, 'article_key', 'articles');
const talentKeys = uniqueBy(talents, 'talent_id', 'talents');
const articleTalents = list('articleTalents').map((row) => {
  const articleKey = text(row.article_key, 'articleTalents.article_key');
  const talentId = text(row.talent_id, 'articleTalents.talent_id');
  if (!articleKeys.has(articleKey)) throw new Error(`articleTalents references article_key not included in proposal: ${articleKey}`);
  if (!talentKeys.has(talentId)) throw new Error(`articleTalents references talent_id not included in proposal: ${talentId}`);
  const confidence = Number(row.confidence);
  if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) throw new Error('articleTalents.confidence must be between 0 and 1.');
  const aliases = typeof row.matched_aliases_json === 'string' ? row.matched_aliases_json : JSON.stringify(row.matched_aliases_json ?? []);
  JSON.parse(aliases);
  return { relation_key: text(row.relation_key, 'articleTalents.relation_key'), article_key: articleKey, talent_id: talentId, matched_aliases_json: aliases, matched_fields: text(row.matched_fields, 'articleTalents.matched_fields'), evidence_text: text(row.evidence_text, 'articleTalents.evidence_text'), confidence, detection_method: text(row.detection_method ?? 'ai_review', 'articleTalents.detection_method'), last_seen_at: text(row.last_seen_at, 'articleTalents.last_seen_at', false) || now };
});
uniqueBy(articleTalents, 'relation_key', 'articleTalents');
return [{ json: { proposalDate: text(proposal.proposalDate ?? now.slice(0, 10), 'proposalDate'), articles, talents, articleTalents, counts: { articles: articles.length, talents: talents.length, articleTalents: articleTalents.length } } }];
